ttl:
PREFIX :             <http://forgetrustee.kickstarttrustee.de/ontology/FAIRWinDS#>
PREFIX dtm-business: <https://forgetrustee.kickstarttrustee.de/ontology/dtm-business#>
PREFIX dtm-core:     <https://forgetrustee.kickstarttrustee.de/ontology/dtm-core#>
PREFIX dtm-data:     <https://forgetrustee.kickstarttrustee.de/ontology/dtm-data#>
PREFIX dtm-legal:    <https://forgetrustee.kickstarttrustee.de/ontology/dtm-legal#>
PREFIX owl:          <http://www.w3.org/2002/07/owl#>
PREFIX rdf:          <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:         <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd:          <http://www.w3.org/2001/XMLSchema#>

:ReceptionFAIRWinDS  rdf:type           dtm-data:DataReception , owl:NamedIndividual;
        rdfs:label                      "ReceptionFAIRWinDS"@de;
        dtm-data:hasReceptionFrequency  dtm-data:Periodic;
        dtm-data:hasReceptionTechnique  dtm-data:ReceptionAPI;
        dtm-data:securedByTechnique     dtm-data:Anonymisation , dtm-data:Pseudonymisation , dtm-data:TransportEncryption , :CustomReceptionSecurityIDS-basierteDateninfrastruktur;
        dtm-data:usesSystem             :SourceSystemWindenergieanlagenWindparksundSystemederWindparkbetreiber .

:Forschungseinrichtungen
        rdf:type                      owl:NamedIndividual , dtm-core:Actor , dtm-core:DataConsumer;
        rdfs:label                    "Forschungseinrichtungen"@de;
        dtm-business:affiliationType  dtm-business:Organisation;
        dtm-business:hasDataConsumerMotivation
                dtm-business:ValueCreation , dtm-business:ScienceAndResearch , dtm-business:Innovation;
        dtm-business:usesPayModelAsDataConsumer
                dtm-business:Free;
        dtm-core:isDataConsumerOf     :FAIRWinDS;
        dtm-core:isGrantedAccess      :BetriebsdatenvonWindenergieanlagen;
        dtm-legal:isBeneficiaryOf     dtm-legal:LegitimateInterest .

:FraunhoferIWES  rdf:type             owl:NamedIndividual , dtm-business:Organisation;
        rdfs:label                    "Fraunhofer IWES"@de;
        dtm-business:affiliationType  dtm-business:Organisation;
        dtm-business:isOperatorOfDataTrustee
                :FAIRWinDS .

:SourceSystemWindenergieanlagenWindparksundSystemederWindparkbetreiber
        rdf:type                 owl:NamedIndividual , dtm-data:SourceSystem;
        rdfs:label               "SourceSystemWindenergieanlagen, Windparks und Systeme der Windparkbetreiber"@de;
        dtm-data:isUsedAsSystem  :ReceptionFAIRWinDS .

:StorageFAIRWinDS  rdf:type           owl:NamedIndividual , dtm-data:DataStorage;
        rdfs:label                    "StorageFAIRWinDS"@de;
        dtm-data:hasRetentionPeriod   dtm-data:WithRetention;
        dtm-data:hasStorageTechnique  dtm-data:CentralStorage;
        dtm-data:performsStorage      :FAIRWinDS .

:ForwardingFAIRWinDS  rdf:type       owl:NamedIndividual , dtm-data:DataForwarding;
        rdfs:label                   "ForwardingFAIRWinDS"@de;
        dtm-data:hasForwardingFrequency
                dtm-data:Periodic;
        dtm-data:hasForwardingTechnique
                dtm-data:ReceptionAPI;
        dtm-data:securedByTechnique  dtm-data:Anonymisation , dtm-data:TransportEncryption , dtm-data:Pseudonymisation;
        dtm-data:usesSystem          :TargetSystemForschungs-undAnalysesystemederbeteiligtenForschungseinrichtungen .

:TargetSystemForschungs-undAnalysesystemederbeteiligtenForschungseinrichtungen
        rdf:type                  owl:NamedIndividual , dtm-data:TargetSystem;
        rdfs:label                "TargetSystemForschungs- und Analysesysteme der beteiligten Forschungseinrichtungen"@de;
        dtm-data:isUsedAsSystemm  :ForwardingFAIRWinDS .

:CustomAnalysisUnternehmensuebergreifendeDatenauswertung
        rdf:type      owl:NamedIndividual , dtm-data:AnalysisTechnique;
        rdfs:comment  "Die Betriebsdaten werden aggregiert ausgewertet, um Potenziale zur Senkung von Stromgestehungskosten zu identifizieren."@de;
        rdfs:label    "CustomAnalysisUnternehmensübergreifende Datenauswertung"@de;
        dtm-data:isDataAnalysisTechniqueOf
                :AnalysisFAIRWinDS .

:DTM_FAIRWinDS  rdf:type               owl:NamedIndividual , dtm-core:ExternallyControlledValueAddedDataTrustee;
        rdfs:label                     "DTM_FAIRWinDS"@de;
        dtm-core:isDataTrusteeModelOf  :FAIRWinDS;
        dtm-data:implementedOn         dtm-data:PeerToPeerArchitecture .

:PreparationFAIRWinDS
        rdf:type    owl:NamedIndividual , dtm-data:DataPreparation;
        rdfs:label  "PreparationFAIRWinDS"@de;
        dtm-data:hasPreparationTechnique
                dtm-data:Aggregation , dtm-data:Transformation , :CustomPreparationStandardisierungvonBetriebsdaten , :CustomPreparationQualitaetspruefungundDatenanreicherung .

:       rdf:type  owl:Ontology .

:CustomReceptionSecurityIDS-basierteDateninfrastruktur
        rdf:type                     owl:NamedIndividual , dtm-data:SecurityReceptionTechnique;
        rdfs:comment                 "Die Bereitstellung und Übertragung der Daten erfolgt innerhalb einer dezentralen Dateninfrastruktur auf Basis der International Data Spaces."@de;
        rdfs:label                   "CustomReceptionSecurityIDS-basierte Dateninfrastruktur"@de;
        dtm-data:securesAsTechnique  :ReceptionFAIRWinDS .

:CustomPreparationStandardisierungvonBetriebsdaten
        rdf:type      owl:NamedIndividual , dtm-data:PreparationTechnique;
        rdfs:comment  "Die Daten werden in ein einheitliches Format überführt und unter Nutzung von Branchenstandards beschrieben."@de;
        rdfs:label    "CustomPreparationStandardisierung von Betriebsdaten"@de;
        dtm-data:isPreparationTechniqueOf
                :PreparationFAIRWinDS .

:FAIRWinDS  rdf:type                   dtm-core:DataTrustee , owl:NamedIndividual;
        rdfs:label                     "FAIRWinDS"@de;
        dtm-business:hasBusinessForm   dtm-business:CooperativeSociety;
        dtm-business:hasDataTrusteeGoal
                dtm-business:Compliance , dtm-business:Innovation , dtm-business:EconomicUtilization , dtm-business:ScienceAndResearch;
        dtm-business:hasDataTrusteeOperator
                :FraunhoferIWES;
        dtm-business:hasDomain         dtm-business:EnergySector;
        dtm-business:hasFundingSource  dtm-business:BMBF , dtm-business:EU;
        dtm-core:dataTrusteeDescription
                "FAIRWinDS ist ein Datentreuhandmodell für den souveränen und standardisierten Austausch von Betriebsdaten aus Windenergieanlagen. Ziel ist es, den kontrollierten Datenaustausch zwischen Windparkbetreibern und Forschenden zu ermöglichen und dadurch Innovation, Forschung und wirtschaftliche Potenziale im Bereich Windenergie zu fördern."@de;
        dtm-core:hasAffectedParty      :Windparkbetreiber;
        dtm-core:hasDataConsumer       :Forschungseinrichtungen;
        dtm-core:hasDataOwner          :Windparkbetreiber;
        dtm-core:hasDataTrusteeModel   :DTM_FAIRWinDS;
        dtm-data:triggersStorage       :StorageFAIRWinDS .

:Windparkbetreiber  rdf:type          dtm-core:DataOwner , owl:NamedIndividual , dtm-core:Actor , dtm-core:AffectedParty;
        rdfs:label                    "Windparkbetreiber"@de;
        dtm-business:affiliationType  dtm-business:Organisation;
        dtm-business:hasDataHolderMotivation
                dtm-business:Interoperability , dtm-business:ScienceAndResearch , dtm-business:Compliance;
        dtm-business:hasRightsHolderMotivation
                dtm-business:SocietalValue;
        dtm-business:usesPayModelAsDataOwner
                dtm-business:Free;
        dtm-core:administers          :BetriebsdatenvonWindenergieanlagen;
        dtm-core:hasRightsOf          :BetriebsdatenvonWindenergieanlagen;
        dtm-core:isAffectedPartyIn    :FAIRWinDS;
        dtm-core:isDataOwnerOf        :FAIRWinDS .

:BetriebsdatenvonWindenergieanlagen
        rdf:type                    owl:NamedIndividual , dtm-core:Data;
        rdfs:comment                "Betriebs-, Zustands- und Felddaten aus Windenergieanlagen und Windparks zur Analyse, Standardisierung und wissenschaftlichen Auswertung."@de;
        rdfs:label                  "Betriebsdaten von Windenergieanlagen"@de;
        dtm-core:administeredBy     :Windparkbetreiber;
        dtm-core:isAccessGrantedTo  :Forschungseinrichtungen;
        dtm-core:isRightlyOwnedBy   :Windparkbetreiber .

:CustomPreparationQualitaetspruefungundDatenanreicherung
        rdf:type      owl:NamedIndividual , dtm-data:PreparationTechnique;
        rdfs:comment  "Die Daten werden geprüft, bewertet und durch zusätzliche Verarbeitungsschritte ergänzt."@de;
        rdfs:label    "CustomPreparationQualitätsprüfung und Datenanreicherung"@de;
        dtm-data:isPreparationTechniqueOf
                :PreparationFAIRWinDS .

:AnalysisFAIRWinDS  rdf:type  owl:NamedIndividual , dtm-data:DataAnalysis;
        rdfs:label  "AnalysisFAIRWinDS"@de;
        dtm-data:hasDataAnalysisTechnique
                dtm-data:StatisticalAnalysis , :CustomAnalysisUnternehmensuebergreifendeDatenauswertung .
